class UnionFind {
    constructor(size) {
        this.parent = new Array(size);
        this.rank = new Array(size).fill(0);
        for (let i = 0; i < size; i++) {
            this.parent[i] = i;
        }
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        let xRoot = this.find(x);
        let yRoot = this.find(y);
        if (xRoot === yRoot) {
            return false;
        }
        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else if (this.rank[xRoot] > this.rank[yRoot]) {
            this.parent[yRoot] = xRoot;
        } else {
            this.parent[yRoot] = xRoot;
            this.rank[xRoot]++;
        }
        return true;
    }
}

function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    let uf = new UnionFind(n);
    let components = n;
    let left = 0;
    let right = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let answer = 0;

    if (components >= k) {
        return answer;
    }

    let low = 0;
    let high = right;
    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let ufTemp = new UnionFind(n);
        let tempComponents = n;
        for (let edge of edges) {
            if (edge[2] > mid) {
                if (ufTemp.union(edge[0], edge[1])) {
                    tempComponents--;
                }
            }
        }
        if (tempComponents >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

