struct UnionFind {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl UnionFind {
    fn new(size: usize) -> Self {
        let parent = (0..size).collect();
        let rank = vec![0; size];
        UnionFind { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) -> bool {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return false;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else if self.rank[x_root] > self.rank[y_root] {
            self.parent[y_root] = x_root;
        } else {
            self.parent[y_root] = x_root;
            self.rank[x_root] += 1;
        }
        true
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut edges = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    let mut uf = UnionFind::new(n);
    let mut components = n;

    if components >= k {
        return 0;
    }

    let max_time = edges.last().map_or(0, |e| e[2]);
    let mut low = 0;
    let mut high = max_time;
    let mut answer = 0;

    while low <= high {
        let mid = (low + high) / 2;
        let mut uf_temp = UnionFind::new(n);
        let mut temp_components = n;
        for edge in &edges {
            if edge[2] > mid {
                if uf_temp.union(edge[0] as usize, edge[1] as usize) {
                    temp_components -= 1;
                }
            }
        }
        if temp_components >= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    answer
}
